import{_ as t,o as A,c as B,a4 as r}from"./chunks/framework.ChErgFjV.js";const s="/my-knowledge/assets/similar-case01.Gto68lsD.png",C="/my-knowledge/assets/similar-case02.B_zR40ra.png",o="/my-knowledge/assets/similar-case03.DR_TRboE.png",a="/my-knowledge/assets/similar-case04.DloZqQou.png",n="/my-knowledge/assets/similar-case05.Db0uIARZ.png",D="/my-knowledge/assets/similar-case06.BKB0OHol.png",x="/my-knowledge/assets/similar-case07.KlLCEKPS.png",e="/my-knowledge/assets/similar-case08.Dfle7L29.png",g="/my-knowledge/assets/similar-case09.bGSKIX5D.png",d="/my-knowledge/assets/similar-case10.DCgbJcmF.png",Q=JSON.parse('{"title":"相似三角形 — 广州中考真题案例与解析","description":"","frontmatter":{"title":"相似三角形 — 广州中考真题案例与解析","date":"2026-07-03T00:00:00.000Z","tags":["相似三角形","广州中考","压轴题"]},"headers":[],"relativePath":"study/junior-math/exam/similar-triangles.md","filePath":"study/junior-math/exam/similar-triangles.md","lastUpdated":null}'),i={name:"study/junior-math/exam/similar-triangles.md"};function l(E,p,h,m,c,P){return A(),B("div",null,[...p[0]||(p[0]=[r('<h1 id="相似三角形-—-广州中考真题案例与解析" tabindex="-1">相似三角形 — 广州中考真题案例与解析 <a class="header-anchor" href="#相似三角形-—-广州中考真题案例与解析" aria-label="Permalink to &quot;相似三角形 — 广州中考真题案例与解析&quot;">​</a></h1><blockquote><p>相似三角形是广州中考几何综合题必备工具，常与圆、二次函数结合考查，分值 6-8 分。</p><p>难度标注：⭐ 基础 | ⭐⭐ 中等 | ⭐⭐⭐ 较难 | ⭐⭐⭐⭐ 压轴</p></blockquote><hr><h2 id="案例-1-平行线截相似-⭐" tabindex="-1">案例 1：平行线截相似 ⭐ <a class="header-anchor" href="#案例-1-平行线截相似-⭐" aria-label="Permalink to &quot;案例 1：平行线截相似 ⭐&quot;">​</a></h2><p><img src="'+s+'" alt="案例1示意图"></p><p><strong>【题目】</strong> 如图，在 ▵ABC 中，DE ∥ BC，AD = 2，DB = 3，DE = 4，求 BC 的长。</p><p><strong>【解析】</strong></p><p>DE ∥ BC，▵ADE ∼ ▵ABC（AA）。</p><p>相似比 = AD/AB = 2/(2+3) = 2/5。</p><p>DE/BC = 2/5，4/BC = 2/5，BC = 10。</p><p><strong>答：BC = 10</strong></p><p><strong>【方法提炼】</strong> 平行线截三角形得相似，相似比等于对应边之比。注意区分&quot;相似比=k&quot;和&quot;面积比=k²&quot;。</p><hr><h2 id="案例-2-相似比与面积比-⭐" tabindex="-1">案例 2：相似比与面积比 ⭐ <a class="header-anchor" href="#案例-2-相似比与面积比-⭐" aria-label="Permalink to &quot;案例 2：相似比与面积比 ⭐&quot;">​</a></h2><p><img src="'+C+'" alt="案例2示意图"></p><p><strong>【题目】</strong> ▵ABC ∼ ▵DEF，相似比为 2:3，▵ABC 的面积为 16，求 ▵DEF 的面积。</p><p><strong>【解析】</strong></p><p>面积比 = 相似比的平方 = (2/3)² = 4/9。</p><p>S▵DEF = 16 × 9/4 = 36。</p><p><strong>答：▵DEF 面积为 36</strong></p><p><strong>【方法提炼】</strong> 核心公式：面积比 = 相似比的平方。这是中考高频易错点——容易把面积比和相似比混淆。</p><hr><h2 id="案例-3-aa-判定相似-⭐⭐" tabindex="-1">案例 3：AA 判定相似 ⭐⭐ <a class="header-anchor" href="#案例-3-aa-判定相似-⭐⭐" aria-label="Permalink to &quot;案例 3：AA 判定相似 ⭐⭐&quot;">​</a></h2><p><img src="'+o+'" alt="案例3示意图"></p><p><strong>【题目】</strong> 在 ▵ABC 中，∠A = 50°，∠B = 70°。在 ▵DEF 中，∠D = 50°，∠E = 70°。▵ABC 与 ▵DEF 是否相似？若相似，写出对应关系。</p><p><strong>【解析】</strong></p><p>▵ABC 中 ∠C = 180° − 50° − 70° = 60°。</p><p>▵DEF 中 ∠F = 180° − 50° − 70° = 60°。</p><p>两三角形三个角分别相等：∠A = ∠D = 50°，∠B = ∠E = 70°，∠C = ∠F = 60°。</p><p>由 AA 判定：▵ABC ∼ ▵DEF。</p><p>对应关系：A↔D，B↔E，C↔F。</p><p><strong>答：▵ABC ∼ ▵DEF，对应顶点 A↔D，B↔E，C↔F</strong></p><p><strong>【方法提炼】</strong> AA 判定是最常用的相似判定方法。两角对应相等即相似，写对应关系时要按角的对应对。</p><hr><h2 id="案例-4-sas-判定相似-⭐⭐" tabindex="-1">案例 4：SAS 判定相似 ⭐⭐ <a class="header-anchor" href="#案例-4-sas-判定相似-⭐⭐" aria-label="Permalink to &quot;案例 4：SAS 判定相似 ⭐⭐&quot;">​</a></h2><p><img src="'+a+'" alt="案例4示意图"></p><p><strong>【题目】</strong> 在 ▵ABC 和 ▵DEF 中，∠A = ∠D = 40°，AB = 6，AC = 9，DE = 4，DF = 6。判断两三角形是否相似。</p><p><strong>【解析】</strong></p><p>夹角相等：∠A = ∠D = 40°。</p><p>检查夹边之比：AB/DE = 6/4 = 3/2，AC/DF = 9/6 = 3/2。</p><p>两边对应成比例且夹角相等，由 SAS 判定：▵ABC ∼ ▵DEF。</p><p><strong>答：▵ABC ∼ ▵DEF（SAS）</strong></p><p><strong>【方法提炼】</strong> SAS 判定关键：两边的比值相等 + 夹角相等。注意两边必须夹同一个角，且比值要对应一致。</p><hr><h2 id="案例-5-射影定理-⭐⭐" tabindex="-1">案例 5：射影定理 ⭐⭐ <a class="header-anchor" href="#案例-5-射影定理-⭐⭐" aria-label="Permalink to &quot;案例 5：射影定理 ⭐⭐&quot;">​</a></h2><p><img src="'+n+'" alt="案例5示意图"></p><p><strong>【题目】</strong> 在 Rt▵ABC 中，∠ACB = 90°，CD ⊥ AB 于 D，AC = 6，BC = 8，求 CD 和 AD 的长。</p><p><strong>【解析】</strong></p><p>AB = √(36 + 64) = 10。</p><p>由面积法：1/2 × AC × BC = 1/2 × AB × CD</p><p>CD = 6 × 8/10 = 24/5。</p><p>射影定理：AD = AC²/AB = 36/10 = 18/5。</p><p>（也可 BD = BC²/AB = 64/10 = 32/5，验证 AD + BD = 18/5 + 32/5 = 10 = AB ✓）</p><p><strong>答：CD = 24/5，AD = 18/5</strong></p><p><strong>【方法提炼】</strong> 直角三角形斜边上的高产生三组相似：▵ACD ∼ ▵CBD ∼ ▵ABC。射影定理（AC²=AD×AB，BC²=BD×AB，CD²=AD×BD）是高频考点。</p><hr><h2 id="案例-6-相似与比例线段-⭐⭐⭐" tabindex="-1">案例 6：相似与比例线段 ⭐⭐⭐ <a class="header-anchor" href="#案例-6-相似与比例线段-⭐⭐⭐" aria-label="Permalink to &quot;案例 6：相似与比例线段 ⭐⭐⭐&quot;">​</a></h2><p><img src="'+D+'" alt="案例6示意图"></p><p><strong>【题目】</strong> 如图，在 ▵ABC 中，D 是 BC 上的点，BD = 2，DC = 3，E 是 AC 上的点，AE = 1，EC = 4。连接 AD、BE 交于点 P。求 AP:PD 的值。</p><p><strong>【解析】</strong></p><p>过 D 作 DF ∥ BE 交 AC 于 F。</p><p>在 ▵BCE 中，DF ∥ BE，D 是 BC 上的点。</p><p>由平行线分线段成比例：CF/CE = CD/CB = 3/5。</p><p>CF = 3/5 × CE = 3/5 × 5 = 3，EF = CE − CF = 5 − 3 = 2。</p><p>但 E 是 AC 上的点，F 也在 AC 上，需要确定 F 的位置。</p><p>EF = CE − CF = 5 − 3 = 2，AF = AE + EF = 1 + 2 = 3。</p><p>在 ▵ADF 中，PE ∥ DF（因为 DF ∥ BE），</p><p>AP/PD = AE/EF = 1/2。</p><p><strong>答：AP:PD = 1:2</strong></p><p><strong>【方法提炼】</strong> 求线段之比，核心方法是&quot;作平行线构造相似&quot;。过交点一侧的端点作平行线，将比例关系传递到已知边上。</p><hr><h2 id="案例-7-相似与圆综合-⭐⭐⭐" tabindex="-1">案例 7：相似与圆综合 ⭐⭐⭐ <a class="header-anchor" href="#案例-7-相似与圆综合-⭐⭐⭐" aria-label="Permalink to &quot;案例 7：相似与圆综合 ⭐⭐⭐&quot;">​</a></h2><p><img src="'+x+'" alt="案例7示意图"></p><p><strong>【题目】</strong> 如图，AB 是 ⊙O 的弦，点 C 在 ⊙O 上且在 AB 异侧，CD ⊥ AB 于 D，AB = 8，CD = 6，⊙O 半径为 5。求点 C 到弦 AB 的距离是否可能为 6？若可能，求 AD 的长。</p><p><strong>【解析】</strong></p><p>圆心 O 到 AB 的距离：由垂径定理，设弦 AB 中点为 E，OE ⊥ AB，AE = 4。</p><p>OE = √(OA² − AE²) = √(25 − 16) = 3。</p><p>C 在 AB 异侧，CD ⊥ AB 于 D。</p><p>如果 C、O 在 AB 同侧，CD = OC 到 AB 的距离 = OE + OC 的投影... 不对，需具体分析。</p><p>设圆心 O 在 AB 上方，距离 AB 为 3。C 在 AB 下方（异侧）。</p><p>C 到 AB 的距离 = CD = 6。</p><p>点 C 到 AB 距离为 6，而圆心到 AB 距离为 3，圆心在 AB 上方 3 处。</p><p>所以 C 在 AB 下方距 AB 为 6 的位置，C 到圆心距离 = 3 + 6 = 9 &gt; 5（半径），不可能在圆上！</p><p>重新审题：CD = 6 可能有问题。让我重新理解题意——C 应该在 AB 同侧（&quot;在 AB 同侧&quot;更合理）。</p><p>修正：C 在 AB 同侧（与圆心同侧），CD = 6。</p><p>C 到 AB 距离 = 6，圆心到 AB 距离 = 3。</p><p>C 在圆心上方（远离 AB），距 AB 为 6，距圆心 = 6 − 3 = 3。</p><p>OC = 3 ≤ 5，C 在圆内或在圆上？C 在圆上需要 OC = 5。</p><p>OC = 3 ≠ 5，C 不在圆上。所以 CD = 6 不可能。</p><p>重新理解：&quot;CD ⊥ AB 于 D&quot;，D 在 AB 上。</p><p>换种方式：C 在 ⊙O 上，CD ⊥ AB，求 CD 的最大值。</p><p>C 在 ⊙O 上运动，到 AB 的最大距离 = 圆心到 AB 距离 + 半径 = 3 + 5 = 8。</p><p>CD = 6 是可能的。此时 C 在 AB 同侧，OC = CD − OE = 6 − 3 = 3。</p><p>不对。CD 是 C 到 AB 的距离，OE 是 O 到 AB 的距离。</p><p>若 C、O 在 AB 同侧：CD = OE + (C 比O 离 AB 更远的距离)。</p><p>设 C 在 O 正上方（远离 AB 方向）：OC = CD − OE = 6 − 3 = 3。C 在圆上需 OC = 5，矛盾。</p><p>设 C 在 O 与 AB 之间：CD = OE − OC 到某方向... 不对。</p><p>正确做法：设 D 在 AB 上，CD ⊥ AB，C 到 AB 距离 = CD = 6。</p><p>O 到 AB 距离 = 3（OE）。</p><p>若 C、O 在 AB 异侧：OC = CD + OE = 6 + 3 = 9 &gt; 5，不可能。</p><p>若 C、O 在 AB 同侧，C 比 O 离 AB 更远：OC = CD − OE = 6 − 3 = 3。</p><p>C 在圆上要求 OC = 5，6 − 3 = 3 ≠ 5。CD = 6 不可能？</p><p>等等，O 到 AB 距离的计算可能有方向性。让我用坐标法。</p><p>设 AB 在 x 轴上，A(−4, 0)，B(4, 0)（AB 中点为原点）。</p><p>圆心 O(0, 3)（在 AB 上方，距 AB 为 3）。</p><p>C 在圆上：C 满足 x² + (y−3)² = 25。</p><p>C 到 AB（x 轴）距离 = |y| = 6，y = 6 或 y = −6。</p><p>y = 6：x² + 9 = 25，x² = 16，x = ±4。</p><p>C(4, 6) 或 C(−4, 6)。验证 CD = 6 ✓。</p><p>D 是 C 在 AB 上的垂足：C(4, 6) 时 D(4, 0)。</p><p>AD = 4 − (−4) = 8 或 AD = |−4 − (−4)| = 0。</p><p>C(4, 6) 时 D(4, 0)，AD = |4 − (−4)| = 8。</p><p>C(−4, 6) 时 D(−4, 0)，AD = |−4 − (−4)| = 0。</p><p><strong>答：CD = 6 可能。AD = 8 或 AD = 0（即 C 在 A 或 B 正上方时）</strong></p><p><strong>【方法提炼】</strong> 圆中与距离相关的问题，坐标法往往比纯几何方法更清晰。设好坐标系后，问题转化为方程求解。</p><hr><h2 id="案例-8-相似三角形与动点-⭐⭐⭐⭐" tabindex="-1">案例 8：相似三角形与动点 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-8-相似三角形与动点-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 8：相似三角形与动点 ⭐⭐⭐⭐&quot;">​</a></h2><p><img src="'+e+'" alt="案例8示意图"></p><p><strong>【题目】</strong> 在矩形 ABCD 中，AB = 6，BC = 8。点 P 从 A 出发沿 AD 方向运动，速度为 1 单位/秒；点 Q 从 B 出发沿 BC 方向运动，速度为 2 单位/秒。同时出发，何时 ▵ABP 与 ▵QCB 相似？</p><p><strong>【解析】</strong></p><p>设运动 t 秒。AP = t（0 ≤ t ≤ 8），BQ = 2t（0 ≤ 2t ≤ 8，即 0 ≤ t ≤ 4）。</p><p>▵ABP 中：∠A = 90°，AB = 6，AP = t，BP = √(36 + t²)。</p><p>▵QCB 中：∠B = 90°（矩形），QC ⊥ BC... 不对。</p><p>∠B = 90°，CB = 8，BQ = 2t，QC = √(64 + 4t²)。</p><p>注意：▵QCB 中，∠QBC 是直角（矩形角 B = 90°），CB = 8，BQ = 2t。</p><p>▵ABP 和 ▵QCB 都是直角三角形。</p><p>情况1：∠ABP 的对应角 = ∠QCB</p><p>▵ABP ∼ ▵QCB，AB 对应 QC，AP 对应 QB：</p><p>AB/QC = AP/QB = BP/CB</p><p>6/√(64+4t²) = t/(2t) = √(36+t²)/8</p><p>由 6/√(64+4t²) = 1/2：</p><p>12 = √(64+4t²)，144 = 64 + 4t²，4t² = 80，t² = 20，t = 2√5</p><p>验证 √(36+20)/8 = √56/8 = 2√14/8 = √14/4</p><p>6/√144 = 6/12 = 1/2 ✓，t/(2t) = 1/2 ✓，但 √14/4 ≠ 1/2。不成立。</p><p>情况2：▵ABP ∼ ▵BCQ（不同对应关系）</p><p>AB/BC = AP/BQ = BP/CQ</p><p>6/8 = t/(2t) = 3/4</p><p>但 t/(2t) = 1/2 ≠ 3/4。不成立。</p><p>情况3：▵ABP ∼ ▵BQC</p><p>AB/BQ = AP/BC = BP/QC</p><p>6/(2t) = t/8</p><p>48 = 2t²，t² = 24，t = 2√6</p><p>验证 t = 2√6 时：</p><p>AP = 2√6 ≤ 8 ✓，BQ = 4√6 ≤ 8？4√6 ≈ 9.8 &gt; 8。不满足！</p><p>t 的范围需满足 BQ = 2t ≤ 8，t ≤ 4。2√6 ≈ 4.9 &gt; 4。不满足。</p><p>情况4：▵ABP ∼ ▵QBC</p><p>AB/QB = AP/BC</p><p>6/(2t) = t/8，48 = 2t²，同上。</p><p>情况5：▵ABP ∼ ▵BCQ</p><p>AB/BC = BP/BQ</p><p>6/8 = √(36+t²)/(2t)</p><p>3/4 = √(36+t²)/(2t)</p><p>3t/2 = √(36+t²)</p><p>9t²/4 = 36 + t²</p><p>9t² = 144 + 4t²</p><p>5t² = 144，t² = 144/5，t = 12√5/5 ≈ 5.37</p><p>t ≤ 4 不满足。</p><p>情况6：▵ABP ∼ ▵QBC</p><p>AB/QB = BP/BC</p><p>6/(2t) = √(36+t²)/8</p><p>48/(2t) = √(36+t²)</p><p>24/t = √(36+t²)</p><p>576/t² = 36 + t²</p><p>576 = 36t² + t&amp;sup4;</p><p>t&amp;sup4; + 36t² − 576 = 0</p><p>设 u = t²：u² + 36u − 576 = 0</p><p>u = (−36 + √(1296+2304))/2 = (−36 + √3600)/2 = (−36+60)/2 = 12</p><p>t = √12 = 2√3 ≈ 3.46 ≤ 4 ✓</p><p>验证：AP = 2√3，BQ = 4√3</p><p>BP = √(36+12) = √48 = 4√3</p><p>QC = √(64+48) = √112 = 4√7</p><p>AB/QB = 6/(4√3)，BP/BC = 4√3/8 = √3/2</p><p>6/(4√3) = 6√3/12 = √3/2 ✓</p><p>AP/QC = 2√3/(4√7) = √3/(2√7) ≠ √3/2。对应关系有误。</p><p>重新整理：对应关系应为 AB ↔ QB, AP ↔ BC, BP ↔ QC</p><p>6/(4√3) = 2√3/8 = √48/√112</p><p>6/(4√3) = √3/2</p><p>2√3/8 = √3/4 ≠ √3/2。不成立。</p><p>看来需要更系统地列出所有可能。两个直角三角形的直角顶点分别是 A 和 B。</p><p>▵ABP：直角在 A，AB=6（直角边），AP=t（直角边），BP=斜边。</p><p>▵QCB：直角在 B，BQ=2t（直角边），CB=8（直角边），QC=斜边。</p><p>对应关系（直角边↔直角边，斜边↔斜边）：</p><p>子情况 a：AB↔BQ，AP↔CB：</p><p>6/(2t) = t/8，t² = 24，t = 2√6 &gt; 4，不满足。</p><p>子情况 b：AB↔CB，AP↔BQ：</p><p>6/8 = t/(2t)，3/4 = 1/2，矛盾。</p><p>所以在这个范围内没有解。但题目问的是&quot;何时相似&quot;，可能是 0 ≤ t ≤ 8（只限制 AP ≤ 8）。</p><p>如果 Q 超出 BC 范围呢？题目说&quot;沿 BC 方向&quot;，所以 BQ ≤ 8，t ≤ 4。</p><p>在 t ≤ 4 范围内，上述情况都不成立。</p><p>再考虑：▵ABP ∼ ▵CBQ（注意顺序不同意味着对应关系不同）</p><p>AB/CB = AP/BQ</p><p>6/8 = t/(2t) = 1/2 ≠ 3/4。矛盾。</p><p>最终结论：</p><p><strong>答：在运动过程中（0 ≤ t ≤ 4），不存在使 ▵ABP 与 ▵QCB 相似的时刻。</strong></p><p><strong>【方法提炼】</strong> 动点相似问题：列出所有可能的对应关系，逐一建方程求解。务必注意变量的取值范围，解出值后要检验。</p><hr><h2 id="案例-9-相似与面积综合-⭐⭐⭐⭐" tabindex="-1">案例 9：相似与面积综合 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-9-相似与面积综合-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 9：相似与面积综合 ⭐⭐⭐⭐&quot;">​</a></h2><p><img src="'+g+'" alt="案例9示意图"></p><p><strong>【题目】</strong> 在 ▵ABC 中，∠BAC = 90°，AB = 4，AC = 3。点 D 在 BC 上，BD = 2，DC = 3。过 D 作 DE ⊥ BC 交 AB 于 E，求 ▵BDE 的面积。</p><p><strong>【解析】</strong></p><p>BC = √(16+9) = 5，BD = 2，DC = 3。</p><p>DE ⊥ BC，∠BDE = 90°。</p><p>在 ▵ABC 中，∠A = 90°。</p><p>▵BDE ∼ ▵BAC（∠B 公共，∠BDE = ∠BAC = 90°）。</p><p>相似比 = BD/BC = 2/5。</p><p>S▵BDE = S▵BAC × (2/5)² = (1/2 × 4 × 3) × 4/25 = 6 × 4/25 = 24/25</p><p><strong>答：S▵BDE = 24/25</strong></p><p><strong>【方法提炼】</strong> 看到垂直+公共角，立刻想到 AA 相似。相似比已知后直接用面积比=相似比的平方。</p><hr><h2 id="案例-10-相似三角形压轴综合-⭐⭐⭐⭐" tabindex="-1">案例 10：相似三角形压轴综合 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-10-相似三角形压轴综合-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 10：相似三角形压轴综合 ⭐⭐⭐⭐&quot;">​</a></h2><p><img src="'+d+'" alt="案例10示意图"></p><p><strong>【题目】</strong> （广州中考风格压轴）在 ▵ABC 中，∠ACB = 90°，AC = 3，BC = 4。点 D 在 AB 上，AD = x（0 &lt; x &lt; 5）。</p><p>（1）过 D 作 DE ⊥ AB 交 AC 于 E，求 AE 关于 x 的函数关系式；</p><p>（2）若 ▵CDE 是等腰三角形，求 x 的值；</p><p>（3）在（1）的条件下，当 ▵ADE 面积最大时，求 x 的值及最大面积。</p><p><strong>【解析】</strong></p><p>AB = 5。cos∠A = AC/AB = 3/5，sin∠A = BC/AB = 4/5。</p><p><strong>（1）</strong> DE ⊥ AB，∠ADE = 90°。</p><p>在 ▵ADE 中：∠A 已知，AD = x，∠ADE = 90°。</p><p>AE = AD/cos∠A = x/(3/5) = 5x/3。</p><p><strong>答：AE = 5x/3</strong></p><p><strong>（2）</strong> ▵CDE 是等腰三角形，需分情况讨论。</p><p>先求 DE 和 CE：</p><p>DE = AD × tan∠A = x × 4/3 = 4x/3。</p><p>CE = AC − AE = 3 − 5x/3 = (9 − 5x)/3。</p><p>CD² = AC² + AD² − 2×AC×AD×cos∠A（不对，D 在 AB 上）</p><p>CD = ?D 在 AB 上，AD = x，BD = 5 − x。</p><p>用坐标法：设 C(0, 0)，A(3, 0)，B(0, 4)。</p><p>AB 方向：从 A(3,0) 到 B(0,4)，参数方程：(3 − 3t/5, 4t/5)（t 为从 A 出发的距离）。</p><p>AD = x 时，D(3 − 3x/5, 4x/5)。</p><p>E 在 AC 上，AC 是 x 轴上从 (0,0) 到 (3,0)。</p><p>DE ⊥ AB：AB 的方向向量 (−3, 4)，AB 的斜率 = −4/3。</p><p>DE 的斜率 = 3/4（垂直）。</p><p>DE 过 D(3−3x/5, 4x/5)，方程：y − 4x/5 = (3/4)(x&#39; − (3−3x/5))</p><p>E 在 y = 0 上：−4x/5 = (3/4)(x&#39; − 3 + 3x/5)</p><p>x&#39; − 3 + 3x/5 = −16x/15</p><p>x&#39; = 3 − 3x/5 − 16x/15 = 3 − 9x/15 − 16x/15 = 3 − 25x/15 = 3 − 5x/3</p><p>E(3 − 5x/3, 0)，AE = 3 − (3 − 5x/3) = 5x/3 ✓（但方向从 A 向 C，所以 AE = 5x/3 在 0 &lt; x ≤ 9/5 时有效）</p><p>CD² = (3−3x/5)² + (4x/5)² = 9 − 18x/5 + 9x²/25 + 16x²/25 = 9 − 18x/5 + x² = x² − 18x/5 + 9</p><p>CE = 3 − 5x/3（取正值，E 在 A 和 C 之间时）</p><p>DE = √((D到E的距离)²)：D(3−3x/5, 4x/5)，E(3−5x/3, 0)</p><p>DE² = (5x/3 − 3x/5)² + (4x/5)² = ((25x − 9x)/15)² + 16x²/25 = (16x/15)² + 16x²/25</p><p>= 256x²/225 + 16x²/25 = 256x²/225 + 144x²/225 = 400x²/225 = 16x²/9</p><p>DE = 4x/3 ✓</p><p>等腰三角形三种情况：</p><p><strong>CD = CE：</strong> x² − 18x/5 + 9 = (3 − 5x/3)² = 9 − 10x + 25x²/9</p><p>x² − 18x/5 + 9 = 9 − 10x + 25x²/9</p><p>9x² − 162x/5 + 81 = 81 − 90x + 25x²</p><p>9x² − 25x² − 162x/5 + 90x = 0</p><p>−16x² + (450x − 162x)/5 = 0</p><p>−16x² + 288x/5 = 0</p><p>x(−16x + 288/5) = 0</p><p>x = 0（舍）或 x = 288/80 = 18/5</p><p>验证：0 &lt; 18/5 = 3.6 &lt; 5 ✓</p><p><strong>CD = DE：</strong> x² − 18x/5 + 9 = 16x²/9</p><p>9x² − 162x/5 + 81 = 16x²</p><p>−7x² − 162x/5 + 81 = 0</p><p>35x² + 162x − 405 = 0</p><p>x = (−162 ± √(26244+56700))/70 = (−162 ± √82944)/70 = (−162 ± 288)/70</p><p>x = 126/70 = 9/5 或 x = −450/70（舍）</p><p>验证：0 &lt; 9/5 &lt; 5 ✓</p><p><strong>CE = DE：</strong> (3 − 5x/3)² = 16x²/9</p><p>9 − 10x + 25x²/9 = 16x²/9</p><p>9 − 10x + 9x²/9 = 0</p><p>9 − 10x + x² = 0</p><p>(x − 1)(x − 9) = 0</p><p>x = 1 或 x = 9（舍，x &gt; 5）</p><p><strong>答：x = 1 或 x = 9/5 或 x = 18/5</strong></p><p><strong>（3）</strong> S▵ADE = 1/2 × AD × DE = 1/2 × x × 4x/3 = 2x²/3</p><p>0 &lt; x ≤ 9/5（保证 E 在 AC 上）</p><p>S = 2x²/3 在 (0, 9/5] 上单调递增。</p><p>x = 9/5 时 S = 2/3 × 81/25 = 54/25。</p><p><strong>答：x = 9/5 时面积最大，最大面积 54/25</strong></p><p><strong>【方法提炼】</strong> 压轴综合题三步走：(1) 建立函数关系式；(2) 等腰三角形分三种情况讨论；(3) 面积最值转化为二次函数最值。坐标法是解几何综合题的万能工具。</p><hr><h2 id="方法总结" tabindex="-1">方法总结 <a class="header-anchor" href="#方法总结" aria-label="Permalink to &quot;方法总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>题型</th><th>核心方法</th><th>难度</th></tr></thead><tbody><tr><td>平行截相似</td><td>平行线截三角形得相似，注意对应边</td><td>⭐</td></tr><tr><td>相似比与面积比</td><td>面积比 = 相似比的平方</td><td>⭐</td></tr><tr><td>AA 判定</td><td>两角对应相等 → 相似</td><td>⭐⭐</td></tr><tr><td>SAS 判定</td><td>两边成比例+夹角相等</td><td>⭐⭐</td></tr><tr><td>射影定理</td><td>直角三角形斜边上的高，三组相似</td><td>⭐⭐</td></tr><tr><td>比例线段</td><td>作平行线构造相似，传递比例</td><td>⭐⭐⭐</td></tr><tr><td>圆与相似</td><td>弦切角/圆周角 → 构造相似</td><td>⭐⭐⭐</td></tr><tr><td>动点相似</td><td>列出所有对应关系，逐一求解</td><td>⭐⭐⭐⭐</td></tr><tr><td>相似与面积</td><td>面积比=相似比的平方，直接转换</td><td>⭐⭐⭐⭐</td></tr><tr><td>压轴综合</td><td>坐标法 + 分类讨论 + 函数最值</td><td>⭐⭐⭐⭐</td></tr></tbody></table>',277)])])}const O=t(i,[["render",l]]);export{Q as __pageData,O as default};
